import"./style-oXTNnaZS.js";const d="/api",l=document.getElementById("loginView"),o=document.getElementById("dashboardView"),i=document.getElementById("loginBtn");let s=null;i.addEventListener("click",async()=>{const n=document.getElementById("adminUser").value,a=document.getElementById("adminPass").value;try{const e=await(await fetch(`${d}/admin/login`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({name:n,password:a})})).json();e.success?(s=e.user.id,l.style.display="none",o.style.display="block",alert("Admin Login Successful!")):alert(e.error)}catch{alert("Login failed.")}});document.getElementById("updateTimeBtn").addEventListener("click",async()=>{const n=document.getElementById("timeStart").value,a=document.getElementById("timeEnd").value;try{const e=await(await fetch(`${d}/admin/time`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({admin_id:s,start_time:n,end_time:a})})).json();e.success?alert("Timer Updated Successfully!"):alert(e.error)}catch{alert("Action failed")}});document.getElementById("addUserBtn").addEventListener("click",async()=>{const n=document.getElementById("regName").value,a=document.getElementById("regEmail").value;try{const e=await(await fetch(`${d}/admin/users`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({admin_id:s,name:n,email:a})})).json();e.success?(alert("User Registered!"),document.getElementById("regName").value="",document.getElementById("regEmail").value=""):alert(e.error)}catch{alert("Action failed")}});document.getElementById("addProbBtn").addEventListener("click",async()=>{const n={admin_id:s,title:document.getElementById("pTitle").value,difficulty:document.getElementById("pDiff").value,description:document.getElementById("pDesc").value,input_format:document.getElementById("pIn").value,output_format:document.getElementById("pOut").value,constraints:document.getElementById("pCons").value,example_in:document.getElementById("pExIn").value,example_out:document.getElementById("pExOut").value,test_cases:document.getElementById("pTest").value};try{const t=await(await fetch(`${d}/admin/problems`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)})).json();t.success?alert("Problem Added Successfully!"):alert(t.error)}catch{alert("Action failed")}});
